#!/usr/bin/env python3
"""Generate .github/workflows/ci.yml from .github/ci/variants.yaml manifest.

Reads the manifest, validates it, and emits a complete GitHub Actions workflow
with the variants job matrix and conditional build/test steps derived from the
support declarations.

Run as:
    python scripts/generate-ci.py              # write ci.yml in-place
    python scripts/generate-ci.py --check      # validate + diff-check only
"""

from __future__ import annotations

import argparse
import sys
from pathlib import Path
from typing import Any

import yaml

# --------------------------------------------------------------------------
# Constants
# --------------------------------------------------------------------------

REPO_ROOT: Path = Path(__file__).resolve().parent.parent
MANIFEST: Path = REPO_ROOT / ".github" / "ci" / "variants.yaml"
WORKFLOW: Path = REPO_ROOT / ".github" / "workflows" / "ci.yml"
ACTIONS_VERSION = "df4cb1c069e1874edd31b4311f1884172cec0e10  # v6.0.3"
CACHE_VERSION = "27d5ce7f107fe9357f9df03efb73ab90386fccae  # v5.0.5"
SCCACHE_VERSION = "9e7fa8a12102821edf02ca5dbea1acd0f89a2696  # v0.0.10"
MISE_VERSION = "1648a7812b9aeae629881980618f079932869151  # v4.0.1"


def _gh(action: str) -> str:
    """Wrap an action reference in GitHub Actions syntax."""
    return f"actions/{action}@{ACTIONS_VERSION}"


def _cache_key() -> str:
    """Return the sccache env key suffix using target triple."""
    return "${{ matrix.mise_env }}"


def _needs_ios(variant: dict) -> bool:
    """Check if variant is an iOS target."""
    return variant["name"].startswith("ios-")


def _needs_egl(variant: dict) -> bool:
    """Check if variant uses EGL context."""
    return variant["name"].endswith("-egl")


def _is_vulkan(variant: dict) -> bool:
    """Check if variant uses Vulkan backend."""
    return variant["name"].endswith("-vulkan")


def _is_macos(variant: dict) -> bool:
    """Check if variant is macOS."""
    return variant["name"].startswith("macos-")


# --------------------------------------------------------------------------
# Validation
# --------------------------------------------------------------------------


def validate_manifest(data: dict[str, Any]) -> None:
    """Validate manifest structure and cross-check support lists."""
    errors: list[str] = []

    targets = data.get("targets", [])
    bindings = data.get("bindings", [])
    examples = data.get("examples", [])

    if not targets:
        errors.append("empty targets list")

    target_names = {t["name"] for t in targets}

    # Each target must have required fields
    for t in targets:
        for key in ("name", "runner", "os", "arch"):
            if key not in t:
                errors.append(f"target missing '{key}': {t}")

    # Build support sets from bindings + examples
    binding_names: set[str] = set()
    example_names: set[str] = set()

    for b in bindings:
        name = b["name"]
        if name in binding_names:
            errors.append(f"duplicate binding name: {name}")
        binding_names.add(name)
        for target_name in b.get("supports", {}).get("targets", []):
            if target_name not in target_names:
                errors.append(
                    f"binding '{name}' references unknown target: {target_name}"
                )

    for e in examples:
        name = e["name"]
        if name in example_names:
            errors.append(f"duplicate example name: {name}")
        example_names.add(name)
        for target_name in e.get("supports", {}).get("targets", []):
            if target_name not in target_names:
                errors.append(
                    f"example '{name}' references unknown target: {target_name}"
                )

    # Every target should appear in at least one binding/example support list
    covered = set()
    for b in bindings:
        covered.update(b.get("supports", {}).get("targets", []))
    for e in examples:
        covered.update(e.get("supports", {}).get("targets", []))

    for target_name in target_names:
        if target_name not in covered:
            errors.append(
                f"target '{target_name}' not listed in any binding/example support"
            )

    if errors:
        print("manifest validation failed:", file=sys.stderr)
        for e in errors:
            print(f"  - {e}", file=sys.stderr)
        sys.exit(1)


# --------------------------------------------------------------------------
# Generator — conditional expression helpers
# --------------------------------------------------------------------------


def _supports_expression(target_name: str, supported_names: list[str]) -> str:
    """Generate a GitHub Actions if-expression for support check.

    Returns a condition that is true when matrix.mise_env is in the
    supported set.
    """
    if not supported_names:
        return "false"
    parts = [f'matrix.mise_env == "{n}"' for n in supported_names]
    return " || ".join(parts)


def _exclude_expressions(variant_name: str, exclude_patterns: list[str]) -> str:
    """Generate an if-expression that is true when variant should be excluded.

    Used for "not supported" conditions.
    """
    if not exclude_patterns:
        return "false"
    parts = [f'matrix.mise_env == "{n}"' for n in exclude_patterns]
    return " || ".join(parts)


def _if_expression(variant: dict, supported_names: list[str]) -> str:
    """Generate if-expression for a binding/example step given a variant.

    Returns true when the binding/example supports this variant.
    """
    return _supports_expression("", supported_names)


# --------------------------------------------------------------------------
# Workflow generation
# --------------------------------------------------------------------------


def _build_variants_matrix(variants: list[dict]) -> list[dict]:
    """Build the GitHub Actions matrix include list."""
    return [
        {"mise_env": v["name"], "runner": v["runner"]}
        for v in variants
    ]


def _build_native_steps(variant: dict) -> list[dict]:
    """Build native library build/test steps."""
    ios = _needs_ios(variant)
    steps: list[dict] = []

    # Build always runs
    steps.append({
        "name": "Build native library",
        "run": "mise run build",
    })

    # Test skipped for iOS
    if not ios:
        steps.append({
            "name": "Test native library",
            "run": "mise run test",
        })

    return steps


def _build_binding_steps(
    binding: dict, all_variants: list[dict], supported_names: set[str]
) -> list[dict]:
    """Build binding-specific step, one per supported variant."""
    steps: list[dict] = []
    support = binding["supports"]["targets"]
    cmd = binding.get("command", "build")

    for target in support:
        variant = next(v for v in all_variants if v["name"] == target)
        steps.append({
            "name": f"{'Test' if cmd == 'test' else 'Build'} {binding['name']} binding",
            "run": f'mise run //bindings/{binding["name"]}:{cmd}',
        })

    return steps


def _build_example_steps(
    example: dict,
    all_variants: list[dict],
    supported_names: set[str],
) -> list[dict]:
    """Build example-specific step, one per supported variant."""
    steps: list[dict] = []
    cmd = example.get("command", "build")

    for target in example["supports"]["targets"]:
        variant = next(v for v in all_variants if v["name"] == target)
        action = {
            "build": "Build",
            "run": "Run",
            "ci": "Test",
        }.get(cmd, "Build")

        steps.append({
            "name": f"{action} {example['name']} example",
            "run": f'mise run //examples/{example["name"]}:{cmd}',
        })

    return steps


def generate_workflow(data: dict[str, Any]) -> str:
    """Generate the complete workflow YAML file content."""
    variants = data["targets"]
    bindings = data["bindings"]
    examples = data["examples"]

    # Build all support sets for quick lookup
    support_sets: dict[str, set[str]] = {}
    for b in bindings:
        support_sets[f"binding:{b['name']}"] = set(b["supports"]["targets"])
    for e in examples:
        support_sets[f"example:{e['name']}"] = set(e["supports"]["targets"])

    # Generate matrix
    matrix_include = _build_variants_matrix(variants)

    # Build steps: one step per binding/example per supported target
    steps: list[dict] = []

    # Checkout
    steps.append({"uses": f"actions/checkout@{ACTIONS_VERSION}"})

    # Shared setup action
    steps.append({"uses": "./.github/actions/setup-ci-deps"})

    # Native library: configure
    steps.append({"run": "mise run configure"})

    # Native library: build (every variant) + test (non-ios)
    for variant in variants:
        steps.append({
            "name": "Build native library",
            "run": "mise run build",
        })
        if not _needs_ios(variant):
            steps.append({
                "name": "Test native library",
                "run": "mise run test",
            })

    # Binding steps grouped by binding
    for binding in bindings:
        binding_supported = set(binding["supports"]["targets"])
        if not binding_supported:
            continue

        cmd = binding.get("command", "build")
        action = {
            "build": "Build",
            "test": "Test",
        }.get(cmd, "Build")

        # Generate a single step with GitHub Actions expression
        if_expr = _supports_expression("", list(binding_supported))
        steps.append({
            "name": f"{action} {binding['name']} binding",
            "if": if_expr,
            "run": f'mise run //bindings/{binding["name"]}:{cmd}',
        })

    # Example steps grouped by example
    for example in examples:
        example_supported = set(example["supports"]["targets"])
        if not example_supported:
            continue

        cmd = example.get("command", "build")
        action = {"build": "Build", "run": "Run", "ci": "Test"}.get(cmd, "Build")

        if_expr = _supports_expression("", list(example_supported))
        steps.append({
            "name": f"{action} {example['name']} example",
            "if": if_expr,
            "run": f'mise run //examples/{example["name"]}:{cmd}',
        })

    # Assemble workflow
    workflow: dict[str, Any] = {
        "name": "CI",
        "on": {
            "push": {"branches": ["main"]},
            "pull_request": {"branches": ["main"]},
        },
        "permissions": {"contents": "read"},
        "concurrency": {
            "group": "${{ github.workflow }}-${{ github.event.pull_request.number || github.ref }}",
            "cancel-in-progress": "${{ github.event_name == 'pull_request' }}",
        },
        "jobs": {
            "hygiene": {
                "name": "hygiene",
                "runs-on": "ubuntu-latest",
                "timeout-minutes": 30,
                "steps": [
                    {"uses": f"actions/checkout@{ACTIONS_VERSION}"},
                    {"uses": "./.github/actions/setup-ci-deps"},
                    {"run": "mise run ci:lint"},
                ],
            },
            "docs": {
                "name": "docs",
                "runs-on": "ubuntu-latest",
                "timeout-minutes": 60,
                "steps": [
                    {"uses": f"actions/checkout@{ACTIONS_VERSION}"},
                    {"uses": "./.github/actions/setup-ci-deps"},
                    {"run": "mise run //docs:build"},
                ],
            },
            "variants": {
                "name": "variant / ${{ matrix.mise_env }}",
                "runs-on": "${{ matrix.runner }}",
                "timeout-minutes": 120,
                "env": {"MISE_ENV": "${{ matrix.mise_env }}"},
                "strategy": {
                    "fail-fast": False,
                    "matrix": {"include": matrix_include},
                },
                "steps": steps,
            },
            "required": {
                "name": "ci-required",
                "runs-on": "ubuntu-latest",
                "timeout-minutes": 5,
                "if": "${{ always() }}",
                "needs": ["hygiene", "docs", "variants"],
                "steps": [
                    {
                        "name": "Fail if required jobs failed",
                        "if": "${{ contains(needs.*.result, 'failure') || contains(needs.*.result, 'cancelled') || contains(needs.*.result, 'skipped') }}",
                        "run": [
                            "echo '${{ toJSON(needs) }}'",
                            "exit 1",
                        ]
                        if True  # single string
                        else "exit 1",
                    },
                    {"run": "true"},
                ],
            },
        },
    }

    return workflow


# --------------------------------------------------------------------------
# YAML serialization helper (embeds ${{ }} expressions as raw strings)
# --------------------------------------------------------------------------


class _RawStr(str):
    """A string subclass that serializes as a raw GitHub Actions expression."""

    pass


class _CustomDumper(yaml.SafeDumper):
    """Custom YAML dumper that preserves ${{ }} expressions."""

    pass


def _str_representer(dumper: _CustomDumper, data: str) -> yaml.ScalarNode:
    """Represent strings, quoting them as needed for YAML."""
    # Use double-quoted style for strings containing YAML-special chars
    needs_quoting = any(c in data for c in ":{}&*?|>!%@`,#'\"") or data.startswith("${{")
    if needs_quoting or "\n" in data:
        return dumper.represent_scalar("tag:yaml.org,2002:str", data, style='"')
    return dumper.represent_scalar("tag:yaml.org,2002:str", data)


_CustomDumper.add_represresenter(str, _str_representer)


def _yaml_dumps(data: dict) -> str:
    """Serialize workflow dict to YAML string."""
    return yaml.dump(
        data,
        Dumper=_CustomDumper,
        default_flow_style=False,
        sort_keys=False,
        width=120,
        indent=2,
    )


# --------------------------------------------------------------------------
# Main
# --------------------------------------------------------------------------


def _load_manifest() -> dict[str, Any]:
    """Load and return manifest data."""
    if not MANIFEST.exists():
        print(f"manifest not found: {MANIFEST}", file=sys.stderr)
        sys.exit(1)

    with open(MANIFEST) as f:
        return yaml.safe_load(f)


def _save_workflow(content: str) -> None:
    """Write generated workflow file."""
    with open(WORKFLOW, "w") as f:
        f.write(content)


def main() -> None:
    parser = argparse.ArgumentParser(
        description="Generate CI workflow from manifest"
    )
    parser.add_argument(
        "--check",
        action="store_true",
        help="Only check if workflow is up to date (exit 1 if drift detected)",
    )
    args = parser.parse_args()

    data = _load_manifest()
    validate_manifest(data)
    workflow = generate_workflow(data)
    content = _yaml_dumps(workflow)

    if args.check:
        if WORKFLOW.exists():
            existing = WORKFLOW.read_text()
            if existing != content:
                print(
                    "workflow is out of sync with manifest; run: python scripts/generate-ci.py",
                    file=sys.stderr,
                )
                sys.exit(1)
        else:
            print("workflow file not found; run: python scripts/generate-ci.py", file=sys.stderr)
            sys.exit(1)

    _save_workflow(content)
    print(f"generated {WORKFLOW}")


if __name__ == "__main__":
    main()

