#!/usr/bin/env python3
"""Generate .github/workflows/ci.yml from .github/ci/variants.yaml manifest.

Reads the manifest, validates it, and emits a complete GitHub Actions workflow
with the variants job matrix and conditional build/test steps derived from the
support declarations.

Run as:
    python scripts/generate-ci.py              # overwrite ci.yml in-place
    python scripts/generate-ci.py --check      # only verify it is already in sync
"""

from __future__ import annotations

import argparse
import sys
from pathlib import Path
from typing import Any

import yaml

# ---------------------------------------------------------------------------
# Constants
# ---------------------------------------------------------------------------

ACTION_VERSION = "df4cb1c069e1874edd31b4311f1884172cec0e10  # v6.0.3"


# ---------------------------------------------------------------------------
# YAML helpers
# ---------------------------------------------------------------------------


class _GHExp(str):
    """Subclass that forces double-quoting in YAML output."""

    pass


class _CustomDumper(yaml.SafeDumper):
    """Add a representer that always double-quotes GH expressions."""

    pass


def _rep_ghe(dumper: _CustomDumper, value: _GHExp) -> yaml.ScalarNode:
    return dumper.represent_scalar("tag:yaml.org,2002:str", str(value), style='"')


def _rep_str(dumper: _CustomDumper, value: str) -> yaml.ScalarNode:
    # Quote if it looks like a GH expression or contains YAML special chars
    if value.startswith("${{") or value.startswith("{{") or any(
        c in value for c in ":{}&*?|>!%@`,#"
    ):
        return dumper.represent_scalar("tag:yaml.org,2002:str", value, style='"')
    return dumper.represent_scalar("tag:yaml.org,2002:str", value)


_CustomDumper.add_representer(_GHExp, _rep_ghe)
_CustomDumper.add_representer(str, _rep_str)


def _gh(text: str) -> _GHExp:
    """Wrap a raw string as a GitHub Actions expression token."""
    return _GHExp(text)


def _build_yaml(data: dict) -> str:
    """Dump *data* to YAML preserving GitHub Actions expressions."""
    return yaml.dump(
        data,
        Dumper=_CustomDumper,
        default_flow_style=False,
        sort_keys=False,
        width=180,
        indent=2,
        explicit_start=False,
    )


# ---------------------------------------------------------------------------
# Manifest loading / validation
# ---------------------------------------------------------------------------

MANIFEST = Path(__file__).resolve().parent.parent / ".github" / "ci" / "variants.yaml"
WORKFLOW = Path(__file__).resolve().parent.parent / ".github" / "workflows" / "ci.yml"


def _load_manifest() -> dict[str, Any]:
    if not MANIFEST.is_file():
        print(f"manifest not found: {MANIFEST}", file=sys.stderr)
        sys.exit(1)
    with open(MANIFEST) as fh:
        return yaml.safe_load(fh)


def _validate(data: dict[str, Any]) -> None:
    errors: list[str] = []
    targets = data.get("targets", [])
    target_names = {t["name"] for t in targets}

    for t in targets:
        for key in ("name", "runner", "os", "arch"):
            if key not in t:
                errors.append(f"target missing '{key}': {t}")

    for section in ("bindings", "examples"):
        for item in data.get(section, []):
            name = item["name"]
            for tn in item.get("supports", {}).get("targets", []):
                if tn not in target_names:
                    errors.append(f"{section} item '{name}' references unknown target: {tn}")

    if errors:
        for e in errors:
            print(f"manifest error: {e}", file=sys.stderr)
        sys.exit(1)


# ---------------------------------------------------------------------------
# Step generation helpers
# ---------------------------------------------------------------------------


def _supports_expr(supported: list[str]) -> _GHExp:
    """Return a boolean GH expression that is true when mise_env is supported."""
    if not supported:
        return _gh("false")
    parts = [_gh(f'matrix.mise_env == "{n}"') for n in supported]
    combined = " || ".join(
        f"({p})" if len(parts) > 1 else str(p) for p in parts
    )
    return _GHExp(combined)


def _needs_ios(variant_name: str) -> bool:
    return variant_name.startswith("ios-")


# ---------------------------------------------------------------------------
# Workflow assembly
# ---------------------------------------------------------------------------


def _assemble(data: dict[str, Any]) -> str:
    variants = data["targets"]
    bindings = data["bindings"]
    examples = data["examples"]

    matrix = []
    for v in variants:
        matrix.append({"mise_env": v["name"], "runner": v["runner"]})

    # --- variants job steps ---
    steps: list[dict] = [
        {"uses": f"actions/checkout@{ACTION_VERSION}"},
        {"uses": "./.github/actions/setup-ci-deps"},
        {"run": "mise run configure"},
        {"name": "Build native library", "run": "mise run build"},
    ]

    # Test native library — skip iOS
    non_ios = [v for v in variants if not _needs_ios(v["name"])]
    steps.append({
        "name": "Test native library",
        "if": _supports_expr([v["name"] for v in non_ios]),
        "run": "mise run test",
    })

    # Bindings — one step each
    for binding in bindings:
        supported = binding["supports"]["targets"]
        cmd = binding.get("command", "build")
        label = "Test" if cmd == "test" else "Build"
        name_expr = f"{label} {binding['name']} binding"
        steps.append({
            "name": name_expr,
            "if": _supports_expr(supported),
            "run": f'mise run //bindings/{binding["name"]}:{cmd}',
        })

    # Examples — one step each
    for example in examples:
        supported = example["supports"]["targets"]
        cmd = example.get("command", "build")
        label = {"build": "Build", "run": "Run", "ci": "Test"}.get(cmd, "Build")
        name_expr = f"{label} {example['name']} example"
        steps.append({
            "name": name_expr,
            "if": _supports_expr(supported),
            "run": f'mise run //examples/{example["name"]}:{cmd}',
        })

    workflow: dict[str, Any] = {
        "name": "CI",
        "on": {
            "push": {"branches": ["main"]},
            "pull_request": {"branches": ["main"]},
        },
        "permissions": {"contents": "read"},
        "concurrency": {
            "group": _gh("${{ github.workflow }}-${{ github.event.pull_request.number || github.ref }}"),
            "cancel-in-progress": _gh("${{ github.event_name == 'pull_request' }}"),
        },
        "jobs": {
            "hygiene": {
                "name": "hygiene",
                "runs-on": "ubuntu-latest",
                "timeout-minutes": 30,
                "steps": [
                    {"uses": f"actions/checkout@{ACTION_VERSION}"},
                    {"uses": "./.github/actions/setup-ci-deps"},
                    {"run": "mise run ci:lint"},
                ],
            },
            "docs": {
                "name": "docs",
                "runs-on": "ubuntu-latest",
                "timeout-minutes": 60,
                "steps": [
                    {"uses": f"actions/checkout@{ACTION_VERSION}"},
                    {"uses": "./.github/actions/setup-ci-deps"},
                    {"run": "mise run //docs:build"},
                ],
            },
            "variants": {
                "name": _gh("variant / ${{ matrix.mise_env }}"),
                "runs-on": _gh("${{ matrix.runner }}"),
                "timeout-minutes": 120,
                "env": {"MISE_ENV": _gh("${{ matrix.mise_env }}")},
                "strategy": {
                    "fail-fast": False,
                    "matrix": {"include": matrix},
                },
                "steps": steps,
            },
            "required": {
                "name": "ci-required",
                "runs-on": "ubuntu-latest",
                "timeout-minutes": 5,
                "if": _gh("${{ always() }}"),
                "needs": ["hygiene", "docs", "variants"],
                "steps": [
                    {
                        "name": "Fail if required jobs failed",
                        "if": _gh(
                            "${{ contains(needs.*.result, 'failure') || contains(needs.*.result, 'cancelled') || contains(needs.*.result, 'skipped') }}"
                        ),
                        "run": "echo '${{ toJSON(needs) }}'\nexit 1",
                    },
                    {"run": "true"},
                ],
            },
        },
    }

    return _build_yaml(workflow)


# ---------------------------------------------------------------------------
# CLI
# ---------------------------------------------------------------------------


def _main() -> None:
    parser = argparse.ArgumentParser(
        description="Generate CI workflow from manifest",
    )
    parser.add_argument(
        "--check",
        action="store_true",
        help="Only verify workflow is in sync (exit 1 if drift)",
    )
    args = parser.parse_args()

    data = _load_manifest()
    _validate(data)
    content = _assemble(data)

    if args.check:
        existing = WORKFLOW.read_text() if WORKFLOW.is_file() else ""
        if existing != content:
            print(
                "workflow is out of sync with manifest",
                file=sys.stderr,
            )
            sys.exit(1)
        print("workflow is up to date")
        return

    WORKFLOW.write_text(content)
    print(f"generated {WORKFLOW}")


if __name__ == "__main__":
    _main()

