"""Tests for scripts/generate-ci.py — uses only stdlib + pyyaml."""

from __future__ import annotations

import unittest
import sys
import yaml
from pathlib import Path

REPO_ROOT = Path(__file__).resolve().parent.parent.parent
sys.path.insert(0, str(REPO_ROOT / "scripts"))

from generate_ci import (  # noqa: E402
    _assemble,
    _validate,
    _gh,
    _GHExp,
    _supports_expr,
    _build_yaml,
)

VALID_MANIFEST = {
    "targets": [
        {
            "name": "linux-x64-vulkan",
            "runner": "ubuntu-latest",
            "os": "linux",
            "arch": "x64",
        },
        {
            "name": "ios-arm64-metal",
            "runner": "macos-latest",
            "os": "ios",
            "arch": "arm64",
        },
    ],
    "bindings": [
        {
            "name": "zig",
            "command": "ci",
            "supports": {"targets": ["linux-x64-vulkan"]},
        },
    ],
    "examples": [
        {
            "name": "zig-map",
            "command": "build",
            "supports": {"targets": ["linux-x64-vulkan"]},
        },
    ],
}


def _load_real_manifest() -> dict:
    manifest_path = REPO_ROOT / ".github" / "ci" / "variants.yaml"
    with open(manifest_path) as f:
        return yaml.safe_load(f)


# ── Manifest validation ────────────────────────────────────────────────────


class TestManifestValidation(unittest.TestCase):
    def test_valid_manifest_passes(self):
        _validate(VALID_MANIFEST)  # should not raise

    def test_unknown_target_reference_fails(self):
        manifest = dict(VALID_MANIFEST)
        manifest["bindings"][0]["supports"] = {
            "targets": ["linux-x64-vulkan", "nonexistent"]
        }
        with self.assertRaises(SystemExit) as exc:
            _validate(manifest)
        self.assertEqual(exc.exception.code, 1)

    def test_missing_target_field_fails(self):
        manifest = dict(VALID_MANIFEST)
        manifest["targets"][0] = {"name": "linux-x64-vulkan"}  # missing runner/os/arch
        with self.assertRaises(SystemExit) as exc:
            _validate(manifest)
        self.assertEqual(exc.exception.code, 1)


# ── YAML helpers ───────────────────────────────────────────────────────────


class TestYamlHelpers(unittest.TestCase):
    def test_gh_wraps_string(self):
        expr = _gh("${{ github.ref }}")
        self.assertIsInstance(expr, _GHExp)
        self.assertEqual(str(expr), "${{ github.ref }}")

    def test_build_yaml_preserves_expressions(self):
        data = {
            "name": "test",
            "expr": _gh("${{ matrix.env }}"),
        }
        output = _build_yaml(data)
        self.assertIn("$", output)
        self.assertIn("{{", output)

    def test_build_yaml_format_is_valid_yaml(self):
        data = {
            "jobs": {
                "test": {"run": "echo hi", "if": _gh("${{ always() }}")},
            }
        }
        output = _build_yaml(data)
        parsed = yaml.safe_load(output)
        self.assertEqual(parsed["jobs"]["test"]["run"], "echo hi")
        self.assertIn("${{ always() }}", parsed["jobs"]["test"]["if"])


# ── Conditional expression generation ─────────────────────────────────────

class TestSupportExpr(unittest.TestCase):
    def test_empty_list_returns_false(self):
        result = _supports_expr([])
        self.assertIn("false", str(result))

    def test_single_target(self):
        result = _supports_expr(["linux-x64-vulkan"])
        result_str = str(result)
        self.assertIn("linux-x64-vulkan", result_str)
        # single target should not be wrapped in parentheses
        self.assertNotIn("(matrix.mise_env", result_str)

    def test_multiple_targets(self):
        result = _supports_expr(["a", "b", "c"])
        result_str = str(result)
        for t in ["a", "b", "c"]:
            self.assertIn(t, result_str)
        self.assertIn("||", result_str)

    def test_all_manifest_targets_produce_valid_expr(self):
        data = _load_real_manifest()
        for binding in data["bindings"]:
            result = _supports_expr(binding["supports"]["targets"])
            result_str = str(result)
            for t in binding["supports"]["targets"]:
                self.assertIn(t, result_str)


# ── Workflow assembly ─────────────────────────────────────────────────────


class TestWorkflowAssembly(unittest.TestCase):
    def test_matrix_contains_all_targets(self):
        workflow_yaml = _assemble(VALID_MANIFEST)
        workflow = yaml.safe_load(workflow_yaml)
        matrix_envs = [
            entry["mise_env"]
            for entry in workflow["jobs"]["variants"]["strategy"]["matrix"]["include"]
        ]
        for t in VALID_MANIFEST["targets"]:
            self.assertIn(t["name"], matrix_envs)

    def test_job_structure(self):
        workflow_yaml = _assemble(VALID_MANIFEST)
        workflow = yaml.safe_load(workflow_yaml)
        jobs = list(workflow["jobs"].keys())
        self.assertIn("hygiene", jobs)
        self.assertIn("docs", jobs)
        self.assertIn("variants", jobs)
        self.assertIn("required", jobs)

    def test_native_library_steps(self):
        workflow_yaml = _assemble(VALID_MANIFEST)
        workflow = yaml.safe_load(workflow_yaml)
        variant_steps = workflow["jobs"]["variants"]["steps"]
        step_names = [s.get("name", "") for s in variant_steps]
        self.assertIn("Build native library", step_names)
        self.assertIn("Test native library", step_names)
        test_step = next(s for s in variant_steps if s.get("name") == "Test native library")
        self.assertIn("if", test_step)

    def test_binding_steps_have_if(self):
        workflow_yaml = _assemble(VALID_MANIFEST)
        workflow = yaml.safe_load(workflow_yaml)
        variant_steps = workflow["jobs"]["variants"]["steps"]
        for binding in VALID_MANIFEST["bindings"]:
            step = next(
                (s for s in variant_steps if binding["name"] in s.get("name", "")),
                None,
            )
            self.assertIsNotNone(step, f"no step for binding {binding['name']}")
            self.assertIn("if", step)

    def test_example_steps_have_if(self):
        workflow_yaml = _assemble(VALID_MANIFEST)
        workflow = yaml.safe_load(workflow_yaml)
        variant_steps = workflow["jobs"]["variants"]["steps"]
        for example in VALID_MANIFEST["examples"]:
            step = next(
                (s for s in variant_steps if example["name"] in s.get("name", "")),
                None,
            )
            self.assertIsNotNone(step, f"no step for example {example['name']}")
            self.assertIn("if", step)

    def test_ios_not_in_test_step(self):
        workflow_yaml = _assemble(VALID_MANIFEST)
        workflow = yaml.safe_load(workflow_yaml)
        variant_steps = workflow["jobs"]["variants"]["steps"]
        test_step = next(s for s in variant_steps if s.get("name") == "Test native library")
        if_str = test_step.get("if", "")
        self.assertNotIn("ios-arm64-metal", if_str)

    def test_required_job_gate(self):
        workflow_yaml = _assemble(VALID_MANIFEST)
        workflow = yaml.safe_load(workflow_yaml)
        required = workflow["jobs"]["required"]
        self.assertEqual(required["if"], "${{ always() }}")
        self.assertEqual(required["needs"], ["hygiene", "docs", "variants"])
        step0 = required["steps"][0]
        self.assertIn("failure", step0["if"])
        self.assertIn("cancelled", step0["if"])
        self.assertIn("skipped", step0["if"])


# ── Real workflow tests ───────────────────────────────────────────────────

class TestRealWorkflowStructure(unittest.TestCase):
    def test_matrix_has_11_entries(self):
        data = _load_real_manifest()
        workflow_yaml = _assemble(data)
        workflow = yaml.safe_load(workflow_yaml)
        matrix = workflow["jobs"]["variants"]["strategy"]["matrix"]["include"]
        self.assertEqual(len(matrix), 11)

    def test_all_11_targets_preserved(self):
        data = _load_real_manifest()
        workflow_yaml = _assemble(data)
        workflow = yaml.safe_load(workflow_yaml)
        matrix_envs = {e["mise_env"] for e in workflow["jobs"]["variants"]["strategy"]["matrix"]["include"]}
        expected = {t["name"] for t in data["targets"]}
        self.assertEqual(matrix_envs, expected)

    def test_runner_mapping(self):
        data = _load_real_manifest()
        workflow_yaml = _assemble(data)
        workflow = yaml.safe_load(workflow_yaml)
        matrix = {e["mise_env"]: e["runner"] for e in workflow["jobs"]["variants"]["strategy"]["matrix"]["include"]}
        expected = {t["name"]: t["runner"] for t in data["targets"]}
        self.assertEqual(matrix, expected)

    def test_binding_count(self):
        data = _load_real_manifest()
        workflow_yaml = _assemble(data)
        workflow = yaml.safe_load(workflow_yaml)
        expected_names = {b["name"] for b in data["bindings"]}
        step_names = [s.get("name", "") for s in workflow["jobs"]["variants"]["steps"]]
        for name in expected_names:
            self.assertTrue(any(name in sn for sn in step_names), f"binding step missing for {name}")

    def test_example_count(self):
        data = _load_real_manifest()
        workflow_yaml = _assemble(data)
        workflow = yaml.safe_load(workflow_yaml)
        expected_names = {e["name"] for e in data["examples"]}
        step_names = [s.get("name", "") for s in workflow["jobs"]["variants"]["steps"]]
        for name in expected_names:
            self.assertTrue(any(name in sn for sn in step_names), f"example step missing for {name}")

    def test_swift_binding_only_macos(self):
        data = _load_real_manifest()
        swift = next(b for b in data["bindings"] if b["name"] == "swift")
        for name in swift["supports"]["targets"]:
            self.assertTrue(
                name.startswith("macos-"),
                f"swift binding shouldn't run on {name}"
            )

    def test_zig_readback_excludes_ios(self):
        data = _load_real_manifest()
        readback = next(e for e in data["examples"] if e["name"] == "zig-readback")
        for t in readback["supports"]["targets"]:
            self.assertFalse(
                t.startswith("ios-"),
                f"zig-readback should exclude iOS target {t}"
            )
        self.assertIn("macos-arm64-egl", readback["supports"]["targets"])

    def test_lwjgl_only_vulkan(self):
        data = _load_real_manifest()
        lwjgl = next(e for e in data["examples"] if e["name"] == "lwjgl-map")
        for t in lwjgl["supports"]["targets"]:
            self.assertTrue(
                t.endswith("-vulkan"),
                f"lwjgl should only run on vulkan targets, got {t}"
            )

    def test_kotlin_native_excludes_arm_windows(self):
        data = _load_real_manifest()
        kotlin = next(b for b in data["bindings"] if b["name"] == "kotlin-native")
        for t in kotlin["supports"]["targets"]:
            self.assertFalse(
                t.startswith("linux-arm64"),
                f"kotlin-native should exclude linux-arm64 target {t}"
            )
            self.assertFalse(
                t.startswith("windows"),
                f"kotlin-native should exclude windows target {t}"
            )
        self.assertNotIn("macos-arm64-egl", kotlin["supports"]["targets"])

    def test_kotlin_native_includes_macos_vulkan(self):
        data = _load_real_manifest()
        kotlin = next(b for b in data["bindings"] if b["name"] == "kotlin-native")
        self.assertIn("macos-arm64-vulkan", kotlin["supports"]["targets"])


# ── Idempotency ────────────────────────────────────────────────────────────

class TestIdempotency(unittest.TestCase):
    def test_generate_twice_same_output(self):
        data = _load_real_manifest()
        out1 = _assemble(data)
        out2 = _assemble(data)
        self.assertEqual(out1, out2)


if __name__ == "__main__":
    unittest.main()

